700→  let believed_player_pos = ref (believed_x, believed_y, believed_z) in
701→  ignore believed_seg;
702→  let obj_ref = objnum lxor frame_count in
703→  (* Helper: compute visibility *)
704→  let compute_vis () =
705→    if !visibility_and_vec_computed = 0
706→    then (
707→      let vpx, vpy, vpz = !vis_vec_pos in
708→      let pv, vtx, vty, vtz, _snd =
709→        Effect.perform (Compute_vis_and_vec (vpx, vpy, vpz))
710→      in
711→      player_visibility := pv;
712→      vec_to_player := vtx, vty, vtz;
713→      (* Mirror compute_vis_and_vec_v2 side effects on local refs.
714→         The effect updates C structs directly, but OCaml's pack_result
715→         would overwrite those with stale local values if we don't
716→         replicate the updates here. *)
717→      (* C lines 2177-2181: wake up resting robots on first clear sight *)
718→      if pv = 2 && !previous_visibility <> 2
719→      then
720→        if !goal_state = ais_rest || !current_state = ais_rest
721→        then (
722→          goal_state := ais_fire;
723→          current_state := ais_fire);
724→      previous_visibility := pv;
725→      if pv <> 0 then time_player_seen := game_time;
726→      visibility_and_vec_computed := 1)
727→  in
728→  (* Helper: unpack path state returned by path effects.
729→     Array: [0]hide_index [1]path_length [2]cur_path_index [3]path_dir
730→            [4]mode [5]goal_segment [6]time_player_seen [7]player_awareness_type
731→            [8]behavior [9]hide_segment [10]skip_ai_count *)
732→  let unpack_path_state ps =
